126→function normalizeMapScope(input: string | null): MapScope {
127→  if (!input) return "bonamoussadi";
128→  const normalized = input.trim().toLowerCase();
129→  if (!allowedMapScopes.has(normalized as MapScope)) return "bonamoussadi";
130→  return normalized as MapScope;
131→}
