242→async function getIpLocation(request: Request): Promise<SubmissionLocation | null> {
243→  const forwarded = request.headers.get("x-forwarded-for");
244→  const realIp = request.headers.get("x-real-ip");
245→  const vercelIp = request.headers.get("x-vercel-forwarded-for");
246→  const ip = normalizeIp(vercelIp ?? forwarded ?? realIp);
247→  if (!ip || isPrivateIp(ip)) return null;
248→  return await fetchIpLocation(ip);
249→}
