251→function validateCreatePayload(category: SubmissionCategory, details: SubmissionDetails): string | null {
252→  const missing = listCreateMissingFields(category, details);
253→  if (missing.length > 0) return `Missing required fields: ${missing.join(", ")}`;
254→  return null;
