257→function getUserDisplayName(userId: string, name: string | null, email: string | null): string {
258→  if (name && name.trim()) return name.trim();
259→  if (email) {
260→    const atIndex = email.indexOf("@");
261→    if (atIndex > 0) return email.slice(0, atIndex);
262→    return email;
263→  }
264→  return userId || "Contributor";
