 95→async function getUserProfileLegacy(id: string): Promise<UserProfile | null> {
 96→  const result = await query<Record<string, unknown>>(
 97→    `
 98→      select id, email, name, image, occupation, xp, password_hash, is_admin, map_scope
 99→      from user_profiles
100→      where id = $1
101→      limit 1
102→    `,
103→    [id],
104→  );
105→
106→  const row = result.rows[0];
107→  if (!row) return null;
108→  return rowToUserProfile(row);
