132→async function getUserProfile(userId: string): Promise<UserProfile | null> {
133→  const id = normalizeUserId(userId);
134→  if (phoneColumnState === "missing") {
135→    return await getUserProfileLegacy(id);
136→  }
137→
138→  try {
139→    const result = await query<Record<string, unknown>>(
140→      `
141→        select id, email, phone, name, image, occupation, xp, password_hash, is_admin, map_scope
142→        from user_profiles
143→        where id = $1
144→        limit 1
145→      `,
146→      [id],
147→    );
148→
149→    const row = result.rows[0];
150→    if (!row) return null;
151→    if (phoneColumnState === "unknown") phoneColumnState = "present";
152→    return rowToUserProfile(row);
153→  } catch (error) {
154→    if (!isMissingPhoneColumnError(error)) throw error;
155→    phoneColumnState = "missing";
156→    return await getUserProfileLegacy(id);
157→  }
158→}
